sql:
SELECT T1.first_name, T1.last_name 
FROM patients AS T1
WHERE T1.patient_id IN (
    SELECT patient_id FROM medical_records
);

SELECT COUNT(*) 
FROM medical_staff 
WHERE role = 'doctor';

SELECT mr.*
FROM medical_records mr
WHERE mr.chol = (
  SELECT MAX(chol)
  FROM medical_records
);

external_knowledge:
heart disease refers to conditions that affect the heart and the blood vessels of the heart; 
cardiologist refers to a doctor who specializes in the diagnosis, treatment, and prevention of disorders related to the heart and the circulatory system; 
hospitalization status 1 indicates that the patient was hospitalized.
